+function extractLastUserText(input: unknown[]): string {
+  for (let i = input.length - 1; i >= 0; i -= 1) {
+    const item = input[i] as Record<string, unknown> | undefined;
+    if (!item || item.role !== "user") continue;
+    const content = item.content;
